#include <bits/stdc++.h>
using namespace std;
int n,m,d[1000006];
string j[1000006];
int main(){
    cin>>n>>m;
    for(int i=1;i<=n;i++)cin>>d[i]>>j[i];
    int p=1;
    while(m--){
        int a,s;
        cin>>a>>s;
        if(d[p]==1)a=(a+1)%2;//统一面向圈内
        if(a==0)p-=s;
        else p+=s;
        if(p<=0)p+=n;
        if(p>n)p%=n;
    }
    cout<<j[p];
    return 0;
}
